Hi,

Below is a program that loads a PEM private key into an `EVP_PKEY` structure:

```
#include <stdio.h>
#include <openssl/evp.h>
#include <openssl/pem.h>

int main(void) {
  EVP_PKEY *pkey = NULL;
  FILE *fd;

  if (!(fd = fopen("/path/to/a/private_key.pem", "r"))) {
    printf("Failed to open the file\n");

    return -1;
  }

  if (PEM_read_PrivateKey(fd, &pkey, NULL, NULL) == NULL) {
    printf("Failed to read the private key\n");

    fclose(fd);

    return -1;
  }

  fclose(fd);

  EVP_PKEY_free(pkey);

  return 0;
}
```

Valgrind reports reachable memory at the end, which seems to come from internal functions:

