```
root@fbsd:~ # pkg install valgrind
root@fbsd:~ # cc -g -x c - -lcrypto -lpthread << EOF && valgrind --extra-debuginfo-path=/usr/lib/debug --leak-check=full ./a.out
#include <openssl/crypto.h>
#include <openssl/opensslv.h>
#include <stdio.h>

int main() {
    OPENSSL_init_crypto(OPENSSL_INIT_NO_ATEXIT, NULL);
    printf("%s\n", OpenSSL_version(OPENSSL_VERSION));
    OPENSSL_thread_stop();
    OPENSSL_cleanup();
    return 0;
}
EOF
```

