**File:** `openssl/apps/lib/apps.c`  
**Function:** `load_key_certs_crls`  
**Version:** OpenSSL `git-master`

### Description

In `load_key_certs_crls()`, objects returned by `OSSL_STORE_INFO_get1_CERT()` and `OSSL_STORE_INFO_get1_CRL()` are passed directly to stack insertion functions. If the insertion fails, the returned objects are not freed, resulting in memory leaks. The following describes the two cases where this can occur.

#### 1. Memory leak when `X509_add_cert()` fails (lines **1052-1063**)

##### Vulnerable Code 
``` c
case OSSL_STORE_INFO_CERT:
    if (pcert != NULL) {
        ok = (*pcert = OSSL_STORE_INFO_get1_CERT(info)) != NULL;
        if (ok)
            pcert = NULL;
    } else if (pcerts != NULL) {
        ok = X509_add_cert(*pcerts,
            OSSL_STORE_INFO_get1_CERT(info),  /* memory allocated here */
            X509_ADD_FLAG_DEFAULT);           /* if X509_add_cert() fails, the returned X509 is leaked here */
    }
    ncerts += ok;
    break;
```
`OSSL_STORE_INFO_get1_CERT(info)` returns a newly allocated `X509` object. If `X509_add_cert()` fails, this object is not inserted into the stack and is never freed.

##### Suggested Fix
``` c
} else if (pcerts != NULL) {
    X509 *cert = OSSL_STORE_INFO_get1_CERT(info);

    ok = cert != NULL
        && X509_add_cert(*pcerts, cert, X509_ADD_FLAG_DEFAULT);
    if (!ok)
        X509_free(cert);
}
```

#### 2. Memory leak when `sk_X509_CRL_push()` fails (lines **1064-1070**)

##### Vulnerable Code 
``` c
case OSSL_STORE_INFO_CRL:
    if (pcrl != NULL) {
        ok = (*pcrl = OSSL_STORE_INFO_get1_CRL(info)) != NULL;
        if (ok)
            pcrl = NULL;
    } else if (pcrls != NULL) {
        ok = sk_X509_CRL_push(*pcrls,
            OSSL_STORE_INFO_get1_CRL(info));  /* memory allocated here; if push fails, the returned X509_CRL is leaked */
    }
    ncrls += ok;
    break;
```
`OSSL_STORE_INFO_get1_CRL(info)` returns a newly allocated `X509_CRL` object. If `sk_X509_CRL_push()` fails, this object is not inserted into the stack and is never freed.

##### Suggested Fix
``` c
} else if (pcrls != NULL) {
    X509_CRL *crl = OSSL_STORE_INFO_get1_CRL(info);

    ok = crl != NULL && sk_X509_CRL_push(*pcrls, crl);
    if (!ok)
        X509_CRL_free(crl);
}
```

**Issue Summary**
A resource leak occurs in the `crls_http_cb` function within `apps/lib/apps.c (lines 2647-2680)`. When the function successfully downloads and pushes the first CRL to the stack but fails to push the second CRL (Delta CRL), it jumps to the `error` label. Inside the error handling block, it uses `sk_X509_CRL_free(crls)` instead of `sk_X509_CRL_pop_free(crls, X509_CRL_free)`. This destroys the stack container but orphans any previously pushed `X509_CRL` objects, leading to a memory leak.

**Problematic Code**

```c
static STACK_OF(X509_CRL) *crls_http_cb(const X509_STORE_CTX *ctx,
    const X509_NAME *nm)
{
    const X509 *x;
    STACK_OF(X509_CRL) *crls = NULL;
    X509_CRL *crl;
    STACK_OF(DIST_POINT) *crldp;

    crls = sk_X509_CRL_new_null();
    if (!crls)
        return NULL;
    x = X509_STORE_CTX_get_current_cert(ctx);
    crldp = X509_get_ext_d2i(x, NID_crl_distribution_points, NULL, NULL);
    crl = load_crl_crldp(crldp);
    sk_DIST_POINT_pop_free(crldp, DIST_POINT_free);

    if (crl == NULL || !sk_X509_CRL_push(crls, crl))
        goto error;

    /* Try to download delta CRL */
    crldp = X509_get_ext_d2i(x, NID_freshest_crl, NULL, NULL);
    crl = load_crl_crldp(crldp);
    sk_DIST_POINT_pop_free(crldp, DIST_POINT_free);

    if (crl != NULL && !sk_X509_CRL_push(crls, crl))
        goto error;

    return crls;

error:
    X509_CRL_free(crl);
    sk_X509_CRL_free(crls);
    return NULL;
}

```

**Root Cause Analysis**
The logical flaw lies in misunderstanding the OpenSSL Safestack API semantics:

1. `sk_X509_CRL_free()` strictly deallocates the stack structure itself (the array holding the pointers) but does **not** free the actual objects the pointers refer to.
2. If `crl = load_crl_crldp(crldp);` succeeds the first time and the CRL is pushed, `crls` assumes ownership of that `X509_CRL` object.
3. If the second `sk_X509_CRL_push(crls, crl)` fails, the code handles the local `crl` correctly via `X509_CRL_free(crl)` but calls `sk_X509_CRL_free(crls)` to destroy the stack.
4. Because `sk_X509_CRL_free` does not clean up its members, the Base CRL loaded in step 1 is permanently leaked.

