        size_t tmplen = keylen;
        unsigned char *key = NULL;
        OSSL_PARAM import_params[2] = { OSSL_PARAM_END, OSSL_PARAM_END };

        if (ctx->op.kex.exchange->derive == NULL) {
            ERR_raise(ERR_R_EVP_LIB, ERR_R_UNSUPPORTED);
            goto cleanup;
        }

        key = OPENSSL_zalloc(keylen);
        if (key == NULL) {
            ERR_raise(ERR_R_EVP_LIB, ERR_R_CRYPTO_LIB);
            goto cleanup;
        }

        if (!ctx->op.kex.exchange->derive(ctx->op.kex.algctx, key, &tmplen,
                tmplen)) {
            OPENSSL_free(key);
            goto cleanup;
        }

        if (keylen != tmplen) {
            OPENSSL_free(key);
            ERR_raise(ERR_R_EVP_LIB, ERR_R_INTERNAL_ERROR);
            goto cleanup;
        }
        import_params[0] = OSSL_PARAM_construct_octet_string(OSSL_SKEY_PARAM_RAW_BYTES,
            key, keylen);

        ret = EVP_SKEY_import_SKEYMGMT(ctx->libctx, skeymgmt,
            OSSL_SKEYMGMT_SELECT_SECRET_KEY, import_params);
        OPENSSL_clear_free(key, keylen);
        goto cleanup;
    }

    ret = evp_skey_alloc(skeymgmt);
    if (ret == NULL)
        goto cleanup;

    ret->keydata = ctx->op.kex.exchange->derive_skey(ctx->op.kex.algctx, key_type,
        ossl_provider_ctx(skeymgmt->prov),
        skeymgmt->import, keylen, params);

    if (ret->keydata == NULL) {
        EVP_SKEY_free(ret);
        ret = NULL;
        goto cleanup;
    }
cleanup:
    if (mgmt != skeymgmt)
        EVP_SKEYMGMT_free(skeymgmt);
    return ret;
}
```

### Note

If this is considered a real leak, I would be happy to submit a PR. If the maintainers would prefer explicit frees on each error path instead of a shared cleanup label, please let me know.

https://github.com/openssl/openssl/blob/master/providers/implementations/ciphers/cipher_aes_gcm_hw_ppc.inc#L87-L122

The function `ppc_aes_gcm_cipher_update()` has a clear contract: return `1` on success, `0` on failure (see line 139: `return 1`). On the decrypt pre-alignment path, line 122 returns `-1` instead of `0` when `CRYPTO_gcm128_decrypt` fails:

```c
// Line 121-122 (decrypt — WRONG):
if (CRYPTO_gcm128_decrypt(&ctx->gcm, in, out, res))
    return -1;

// Line 97-98 (encrypt — CORRECT):
if (CRYPTO_gcm128_encrypt(&ctx->gcm, in, out, res))
    return 0;
```

The caller at `ciphercommon_gcm.c:460` checks:
```c
if (!hw->cipherupdate(ctx, in, len, out))
    goto err;
```

Since `!(-1)` evaluates to `0` (false in C), the `goto err` is **not** taken. The error is silently swallowed and GCM processing continues with potentially corrupt state. This is the **only** `return -1` across all GCM cipher implementation files — all five other error returns in the same function correctly return `0`.

**Version: ** master, commit `3b8e522ae2767f3e2cf579499864d19749e03ea0`
In `crypto/slh_dsa/slh_dsa.c`, function `slh_sign_internal()`, line 123 unconditionally sets `ret = 1`, overwriting the result of the FORS sign / FORS public-key recovery / HT sign chain on lines 113-121:
```
 ret = ossl_slh_fors_sign(hctx, md, sk_seed, pk_seed, adrs, wpkt)
     && PACKET_buf_init(rpkt, sig_fors, WPACKET_get_curr(wpkt) - sig_fors)
     && ossl_slh_fors_pk_from_sig(hctx, rpkt, md, pk_seed, adrs, pk_fors, sizeof(pk_fors))
     && ossl_slh_ht_sign(hctx, pk_fors, sk_seed, pk_seed, tree_id, leaf_id, wpkt);
 *sig_len = sig_len_expected;
 ret = 1; // unconditionally overwrites ret
err:
 if (!WPACKET_finish(wpkt))
     ret = 0;
 return ret;
```
If any of the operations in that chain fail, the function can still report success. In addition, line 122 unconditionally sets `*sig_len` to the expected length even when signing failed.[/+]
This means callers may treat an invalid or incomplete SLH-DSA signature as a successful signing result, with the failure only surfacing later during verification.

A minimal fix is to preserve the result of the chained operations and only set `*sig_len` on success:
```
 if (!ret)
     goto err;
 *sig_len = sig_len_expected;
```
